                    float normalized = (xLocal_(i) - mean) / var;
                    xLocal_(i) = normalized * gammaLocal_(i) + betaLocal_(i);
                }
            }

            // Write output row
            AscendC::DataCopy(yGm_[row * totalO_], xLocal_, totalO_);
        }
